const { logo_public_id, products, devis_id } = $input.first().json;

const CLOUD = 'djq5gqxmj';

// Mapping produit → mockup de base + paramètres overlay
const MAPPING = {
  polos:      { label: 'Polos',            base: 'tenuepro/mockups/polos-base',      w: 200, gravity: 'north_west', x: 80,  y: 80  },
  tshirts:    { label: 'T-shirts',         base: 'tenuepro/mockups/tshirts-base',    w: 200, gravity: 'north_west', x: 80,  y: 80  },
  vestes:     { label: 'Vestes & Sweats',  base: 'tenuepro/mockups/vestes-base',     w: 180, gravity: 'north_west', x: 60,  y: 60  },
  casquettes: { label: 'Casquettes',       base: 'tenuepro/mockups/casquettes-base', w: 120, gravity: 'center',     x: 0,   y: -20 },
  tabliers:   { label: 'Tabliers',         base: 'tenuepro/mockups/tabliers-base',   w: 160, gravity: 'north',      x: 0,   y: 80  },
  chemises:   { label: 'Chemises',         base: 'tenuepro/mockups/chemises-base',   w: 180, gravity: 'north_west', x: 80,  y: 80  },
  sacs:       { label: 'Sacs & Tote bags', base: 'tenuepro/mockups/sacs-base',       w: 200, gravity: 'center',     x: 0,   y: 0   },
};

// Encode le public_id pour Cloudinary (/ → :)
const encodeId = (id) => id.replace(/\//g, ':');

const logoEncoded = encodeId(logo_public_id);
const productList = Array.isArray(products) ? products : [products];

const mockups = productList
  .filter(id => MAPPING[id])
  .map(id => {
    const { label, base, w, gravity, x, y } = MAPPING[id];
    const hasOffset = x !== 0 || y !== 0;
    const transform = hasOffset
      ? `l_${logoEncoded},w_${w},c_fit,g_${gravity},x_${x},y_${y}`
      : `l_${logoEncoded},w_${w},c_fit,g_${gravity}`;
    return {
      product_id:  id,
      product:     label,
      mockup_url:  `https://res.cloudinary.com/${CLOUD}/image/upload/${transform}/${base}`,
    };
  });

return [{
  json: {
    devis_id,
    logo_public_id,
    mockups,
    generated_at: new Date().toISOString(),
    count: mockups.length,
  }
}];
